package org.eclipse.jdt.internal.ui;

public class JavaPluginImages {
    public static final String T_ICON = "icons/";
    public static final String T_PREFIX = T_ICON + "etool16/";
    public static final String T_ELCL = T_PREFIX + "elcl16/";
    public static final String NAME_PREFIX = T_ICON + "full/obj16/";

    public static final String IMAGE_ALREADY_GIF = NAME_PREFIX + "some_image.gif"; // Already .gif, should not change
    public static final String IMAGE_NON_MATCHING_PREFIX = "/another/path/image.png"; // Different prefix, should not match
    public static final String IMAGE_DYNAMIC_NAME = NAME_PREFIX + getDynamicImageName(); // Not a string literal, should not match
    public static final String IMAGE_DIFFERENT_EXTENSION = NAME_PREFIX + "text_file.txt"; // Different extension, should not match
    public static final String IMAGE_CASE_SENSITIVE = NAME_PREFIX + "image.PNG"; // Capitalized PNG, should not match (map keys are exact)

    private static String getDynamicImageName() {
        return "dynamic.png";
    }
}
